#include "bh1750.h"
#include <Wire.h>
#include <BH1750.h>
static BH1750 lm;
static float _lux=0;
static unsigned long _last=0;
void bh1750_setup(){Wire.begin();if(!lm.begin(BH1750::CONTINUOUS_HIGH_RES_MODE)){Serial.println("[bh1750] Fail!");return;}Serial.println("[bh1750] OK");}
void bh1750_loop(){if(millis()-_last<500)return;_last=millis();if(lm.measurementReady())_lux=lm.readLightLevel();}
float bh1750_get_lux(){return _lux;}
